text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        {
          "topic": "릴리스 목표",
          "detail": "공개 릴리스 목표는 금요일 15:00 KST로 확정되며, 스모크 테스트 통과 시에만 진행한다."
        },
        {
          "topic": "packageName 불일치 처리 방식",
          "detail": "smoke-theme-pack.mjs의 packageName 불일치 무시 제안은 폐기. 실제 처리 방향은 package config를 먼저 점검하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
        },
        {
          "topic": "Smoke test 후속 액션",
          "detail": "Minjun이 금요일 10:00 KST까지 Smoke test를 재실행하고 결과를 공유한다."
        },
        {
          "topic": "실패 분석 액션",
          "detail": "Doyun이 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다."
        },
        {
          "topic": "Tarball 경로 확인",
          "detail": "Hara가 Minjun의 Smoke 결과 업로드 후 생성된 tarball 경로를 확인한다."
        }
      ],
      "rejected_proposals": [
        {
          "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
          "result": "반려됨",
          "reason": "불일치 자체보다 계약/패키지 설정 점검이 선행되어야 하므로"
        }
      ],
      "stretch_goals": [
        {
          "item": "수요일 릴리스 완료",
          "status": "내부 Stretch Goal",
          "note": "최종 공개 릴리스 결정이 아니라 내부 목표로만 다룸"
        }
      ]
    },
    "non_decisions": [
      {
        "item": "README 설치 절차 검토",
        "detail": "Seoyeon이 가능하면 목요일 검토 제안했으나, 소유자/확정 일정은 없음."
      },
      {
        "item": "수요일 목표 공개 언급 여부",
        "detail": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부 미정."
      }
    ],
    "risks": [
      {
        "item": "Tarball 경로 오류",
        "impact": "릴리스 지연 가능성"
      },
      {
        "item": "README 설치 단계 노후화",
        "impact": "릴리스 노트/안내가 사용자에게 오도될 위험"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "미해결"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 반영할지 여부",
        "status": "미해결"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "Smoke 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 Smoke 결과 게시 후 생성된 tarball 경로를 확인한다.",
      "due": "미정(조건: Minjun 결과 공유 후)",
      "status": "확정",
      "source_certainty": "high"
    }
  ],
  "followup_note": {
    "next_to_check": [
      "Minjun의 Smoke 결과(통과/실패)와 공유 상태를 우선 확인한다.",
      "Smoke 실패 시 packageName 불일치가 있는지, 먼저 package config 문제인지 스크립트 문제인지 구분한다.",
      "Hara가 확인한 tarball 경로가 배포 산출물과 일치하는지 검증한다.",
      "Doyun의 action_items.md 트리아지 노트 작성 여부 및 내용 일치성을 확인한다.",
      "최종 승인 권한자와 릴리스 노트에 수요일 stretch goal 반영 여부를 별도 결재/결정 대상으로 확정한다."
    ],
    "what_not_to_invent": [
      "고객/파트너명, 예산, 보안 사고, 생산 장애, 법적 승인, 새 소유자, 미확정 마감일을 임의로 생성하지 않는다.",
      "README 검토의 수행자와 최종 제출 기한을 추정해 지정하지 않는다.",
      "수요일 항목을 공개 릴리스 최종 일정으로 확정하지 않는다."
    ]
  },
  "non_invention_rules": [
    "실제 발언/기록에서 없는 고객, 예산, 보안 이슈, 장애, 법무 승인, 소유자, 확정 마감일을 추가로 만들지 않는다.",
    "내부 제안(Stretch Goal)은 공개 확정 결정과 구분한다.",
    "기존 합의가 아닌 추측 기반(예: 최종 승인자 추정, 예산 책임자 추정)을 기록하지 않는다.",
    "마감 시간은 원문에 명시된 값만 사용하고, 조건부/권장 표현은 원문 표현 그대로 유지한다."
  ]
}
